// frontend/src/pages/EditPostPage.js
import { useState, useEffect } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import API from '../api/axios';

const EditPostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [title, setTitle]   = useState('');
  const [body, setBody]     = useState('');
  const [image, setImage]   = useState(null);
  const [currentImage, setCurrentImage] = useState('');
  const [error, setError]   = useState('');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving]   = useState(false);

  useEffect(() => {
    API.get(`/posts/${id}`)
      .then(res => {
        const post = res.data;
        // Only the owner or admin should be here — ProtectedRoute handles auth
        setTitle(post.title);
        setBody(post.body);
        setCurrentImage(post.image || '');
      })
      .catch(() => setError('Failed to load post.'))
      .finally(() => setLoading(false));
  }, [id]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSaving(true);

    const fd = new FormData();
    fd.append('title', title);
    fd.append('body', body);
    if (image) fd.append('image', image);

    try {
      await API.put(`/posts/${id}`, fd);
      navigate(`/posts/${id}`);
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save changes.');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className="content"><p>Loading post...</p></div>;

  return (
    <div className="content">
      <h2>✏️ Edit Post</h2>

      {error && (
        <p style={{
          color: '#7a1a1a',
          background: 'rgba(180,60,60,0.12)',
          border: '1px solid #b43c3c',
          borderRadius: '8px',
          padding: '10px 16px',
          marginBottom: '16px',
        }}>
          {error}
        </p>
      )}

      <form onSubmit={handleSubmit}>
        <label htmlFor="edit-title">Post Title:</label>
        <input
          id="edit-title"
          type="text"
          value={title}
          onChange={e => setTitle(e.target.value)}
          required
        />

        <label htmlFor="edit-body">Post Content:</label>
        <textarea
          id="edit-body"
          rows="14"
          value={body}
          onChange={e => setBody(e.target.value)}
          required
          style={{ width: '100%' }}
        />

        {/* Show current image */}
        {currentImage && (
          <div style={{ margin: '12px 0' }}>
            <label>Current Cover Image:</label>
            <img
              src={`http://localhost:5000/uploads/${currentImage}`}
              alt="Current cover"
              style={{ maxWidth: '200px', display: 'block', marginTop: '8px', borderRadius: '8px' }}
            />
          </div>
        )}

        {/* Image upload — admin only */}
        {user?.role === 'admin' && (
          <div style={{ margin: '12px 0' }}>
            <label htmlFor="edit-image">Replace Cover Image (Admin only):</label>
            <input
              id="edit-image"
              type="file"
              accept="image/*"
              onChange={e => setImage(e.target.files[0])}
            />
          </div>
        )}

        <div style={{ display: 'flex', gap: '12px', marginTop: '8px' }}>
          <input
            type="submit"
            id="newcolor"
            value={saving ? 'Saving...' : 'Save Changes'}
            disabled={saving}
          />
          <Link
            to={`/posts/${id}`}
            style={{
              padding: '15px 20px',
              background: 'transparent',
              border: '2px solid #475522',
              color: '#475522',
              borderRadius: '4px',
              textDecoration: 'none',
              fontWeight: 'bold',
              fontSize: '0.95rem',
            }}
          >
            Cancel
          </Link>
        </div>
      </form>
    </div>
  );
};

export default EditPostPage;
